import { Box, Divider, Drawer, Typography } from '@mui/material'
import React, { useState } from 'react'
import { MenuItem } from '@mui/material'
import AddCircle from 'src/assets/IconSet/AddOutlined'
import ProgramListView from './ProgramListView'
import SendProgramPage from './SendProgramDrawer'
import { useNavigate } from 'react-router'
function ActionBottomDrawer(props) {
    const [drawerOpen, setDrawerOpen] = useState(false)
    const [selectedProgram, setSelectedProgram] = useState(null)
    const navigate = useNavigate()
    const toggleDrawer = (isOpen) => (event) => {

        if (
            event &&
            event.type === 'keydown' &&
            (event.key === 'Tab' || event.key === 'Shift')
        ) {
            return
        }

        setDrawerOpen(isOpen)
        setSelectedProgram(null)
    }

    return (
        <div>
            <Drawer
                anchor={'bottom'}
                PaperProps={{
                    style: {
                        backgroundColor: 'transparent',
                        boxShadow: 'none',
                    },
                }}
                disableBackdropTransition
                open={drawerOpen}
                onClose={toggleDrawer(false)}
                onOpen={toggleDrawer(true)}
            >
                <Box
                    padding={'24px 24px 36px'}
                    style={{
                        borderTopLeftRadius: '16px',
                        borderTopRightRadius: '16px',
                        backgroundColor: '#fff',
                    }}
                >
                    <Box display="flex" flexDirection="column" component="form">
                        <Box
                            display={'flex'}
                            justifyContent={'space-between'}
                            alignItems={'center'}
                            sx={{ textTransform: 'capitalize' }}
                        >
                            <Typography variant="h3">
                                {selectedProgram?"Enter details":"Select a program"}
                            </Typography>
                        </Box>

                       {props?.title&& <Divider sx={{ my: 1,mb:2 }} />}
                     {selectedProgram?
                     <SendProgramPage  
                     handleDone={()=>{
                            setDrawerOpen(false)
                            props.reload()
                            setSelectedProgram(null)
                        }}
                     Program={selectedProgram}
                     email={props.email}
                     
                     /> :<ProgramListView 
                       onClick={(program) => {
                        navigate(`/sendProgram/${program._id}`,{
                            state:{
                                email:props.email
                            }
                        })
                        setSelectedProgram(program)
                       }}
                       programs={props.programs} />}
                        {/* {props.items.map((i) => (
                            <>
                                <MenuItem
                                    sx={{ px: 0 }}
                                    onClick={() => {
                                        i.onClick()
                                        setDrawerOpen(false)
                                    }}
                                >
                                    {i.icon}
                                    <Typography
                                        align="center"
                                        variant="body"
                                        color={
                                            i.isError
                                                ? 'error.main'
                                                : 'text.primary'
                                        }
                                    >
                                        {i.title}
                                    </Typography>
                                </MenuItem>
                            </>
                        ))} */}
                    </Box>
                </Box>
            </Drawer>
            <div
                onClick={(e) => {
                    e.stopPropagation()
                    setDrawerOpen(true)
                }}
            >
                {props.children}
            </div>
        </div>
    )
}

export default ActionBottomDrawer
